sp_widget.client_script:
api.controller = function() {
    var c = this;
    c.showForm = false;
    c.submitting = false;
    c.newEvent = {};

    c.toggleForm = function() {
        c.showForm = !c.showForm;
        if (c.showForm) {
            c.newEvent = {};
            c.data.successMsg = '';
            c.data.errorMsg = '';
        }
    };

    c.createEvent = function() {
        if (c.submitting) return;
        if (!c.newEvent.title || !c.newEvent.club) {
            c.data.errorMsg = 'Please fill in at least the Title and Club fields.';
            return;
        }
        c.submitting = true;
        c.data.successMsg = '';
        c.data.errorMsg = '';

        c.server.get({
            action: 'create_event',
            title: c.newEvent.title,
            description: c.newEvent.description || '',
            venue: c.newEvent.venue || '',
            event_date: c.newEvent.event_date || '',
            start_time: c.newEvent.start_time || '',
            end_time: c.newEvent.end_time || '',
            capacity: c.newEvent.capacity || '0',
            scope: c.newEvent.scope || 'college_only',
            club: c.newEvent.club
        }).then(function(r) {
            c.data = r.data;
            c.submitting = false;
            if (r.data.successMsg) {
                c.showForm = false;
                c.newEvent = {};
            }
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.submitting = false;
        });
    };

    c.updateStatus = function(event, status) {
        if (c.submitting) return;
        c.submitting = true;
        c.data.successMsg = '';
        c.data.errorMsg = '';

        c.server.get({
            action: 'update_status',
            event_id: event.sys_id,
            new_status: status
        }).then(function(r) {
            c.data = r.data;
            c.submitting = false;
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.submitting = false;
        });
    };
};

sp_widget.css:
.sp-manage-events .panel-heading {
    padding: 12px 20px;
}
.sp-manage-events .panel-title {
    font-size: 16px;
    font-weight: 600;
    color: $text-color;
    line-height: 30px;
}
.sp-manage-events .panel-title .glyphicon {
    margin-right: 8px;
    color: $brand-primary;
}
.sp-create-form {
    background: $background-secondary;
    border: 1px solid $border-tertiary;
    border-radius: 4px;
    padding: 20px;
    margin-bottom: 24px;
}
.sp-create-form h4 {
    margin-top: 0;
    margin-bottom: 16px;
    font-weight: 600;
    color: $text-color;
}
.sp-btn-primary {
    background: $brand-primary;
    border: none;
    color: $btn-primary-color;
    font-weight: 500;
    &:hover:not(:disabled) {
        background: $brand-primary-dark;
        box-shadow: 0 2px 8px rgba($brand-primary, 0.3);
        color: $btn-primary-color;
    }
    &:disabled {
        opacity: 0.6;
        cursor: not-allowed;
    }
}
.sp-input:focus {
    border-color: $brand-primary;
    box-shadow: 0 0 0 2px rgba($brand-primary, 0.15);
}

sp_widget.script:
(function() {
    data.events = [];
    data.clubs = [];
    data.message = '';
    data.successMsg = '';
    data.errorMsg = '';
    data.isAdmin = false;

    try {
        var userId = gs.getUserID();

        // Find clubs where user is president or vice_president
        var clubIds = [];
        var memGr = new GlideRecord('x_2097092_linq_club_membership');
        memGr.addQuery('member', userId);
        memGr.addQuery('role', 'IN', 'president,vice_president');
        memGr.addQuery('status', 'active');
        memGr.setLimit(50);
        memGr.query();

        while (memGr.next()) {
            var clubId = memGr.getValue('club') + '';
            clubIds.push(clubId);
        }

        if (clubIds.length === 0) {
            data.message = 'You are not an admin of any clubs.';
            return;
        }

        data.isAdmin = true;

        // Get club details for dropdown
        var clubGr = new GlideRecord('x_2097092_linq_club');
        clubGr.addQuery('sys_id', 'IN', clubIds.join(','));
        clubGr.setLimit(50);
        clubGr.query();

        while (clubGr.next()) {
            data.clubs.push({
                sys_id: clubGr.getUniqueValue(),
                name: clubGr.getValue('name') + ''
            });
        }

        // Handle create event action
        if (input && input.action === 'create_event') {
            var newEvent = new GlideRecord('x_2097092_linq_event');
            newEvent.initialize();
            newEvent.setValue('title', input.title || '');
            newEvent.setValue('description', input.description || '');
            newEvent.setValue('venue', input.venue || '');
            newEvent.setValue('event_date', input.event_date || '');
            newEvent.setValue('start_time', input.start_time || '');
            newEvent.setValue('end_time', input.end_time || '');
            newEvent.setValue('capacity', input.capacity || '0');
            newEvent.setValue('scope', input.scope || 'college_only');
            newEvent.setValue('club', input.club || '');
            newEvent.setValue('status', 'draft');

            var newId = newEvent.insert();
            if (newId) {
                data.successMsg = 'Event created successfully!';
            } else {
                data.errorMsg = 'Failed to create event. Please try again.';
            }
        }

        // Handle update status action
        if (input && input.action === 'update_status') {
            var updGr = new GlideRecord('x_2097092_linq_event');
            if (updGr.get(input.event_id)) {
                updGr.setValue('status', input.new_status);
                updGr.update();
                data.successMsg = 'Event status updated to ' + input.new_status + '.';
            } else {
                data.errorMsg = 'Event not found.';
            }
        }

        // Load all events for managed clubs
        var evGr = new GlideRecord('x_2097092_linq_event');
        evGr.addQuery('club', 'IN', clubIds.join(','));
        evGr.orderByDesc('event_date');
        evGr.setLimit(100);
        evGr.query();

        while (evGr.next()) {
            data.events.push({
                sys_id: evGr.getUniqueValue(),
                title: evGr.getValue('title') + '',
                club_name: evGr.getDisplayValue('club') + '',
                event_date: evGr.getDisplayValue('event_date') + '',
                status: evGr.getValue('status') + '',
                venue: evGr.getValue('venue') + ''
            });
        }
    } catch (e) {
        gs.error('linq-admin-manage-events error: ' + e.message);
        data.errorMsg = 'An error occurred.';
    }
})();
